const input = $json || {};

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

const rawData = clean(input.callback_data);
const parts = rawData.split("|");
let action = clean(input.action);
let orderId = clean(input.order_id).toUpperCase();
let documentId = clean(input.document_id);
let conversationId = clean(input.conversation_id);

if (parts.length >= 1 && parts[0]) {
  if (parts[0] === "quote_send") action = "send_latest_quote_confirmed";
  if (parts[0] === "quote_cancel") action = "cancel_quote_send";
}
if (!orderId && parts[1]) orderId = clean(parts[1]).toUpperCase();
if (!documentId && parts[2]) documentId = clean(parts[2]);
if (!conversationId && parts[3]) conversationId = clean(parts[3]);

let validationError = "";
if (action === "send_latest_quote_confirmed") {
  if (!orderId || !documentId || !conversationId) {
    validationError = "Missing order, document, or conversation data for quote send.";
    action = "invalid_document_send_callback";
  }
} else if (action === "cancel_quote_send") {
  if (!orderId || !documentId) {
    validationError = "Missing order or document data for quote send cancellation.";
    action = "invalid_document_send_callback";
  }
} else {
  validationError = "Unsupported document-send callback.";
  action = "invalid_document_send_callback";
}

return [{
  json: {
    action,
    validation_error: validationError,
    callback_data: rawData,
    order_id: orderId,
    document_id: documentId,
    conversation_id: conversationId,
    chat_id: clean(input.chat_id),
    callback_query_id: clean(input.callback_query_id),
    clicked_by: clean(input.clicked_by) || "Oom Sakkie",
    telegram_user_id: clean(input.telegram_user_id),
    send_url: orderId ? `https://amadeus-pig-tracking-system.onrender.com/api/orders/${encodeURIComponent(orderId)}/quote/send-latest-confirmed` : "",
    send_body: {
      document_id: documentId,
      conversation_id: conversationId,
      sent_by: clean(input.clicked_by) || "Oom Sakkie",
      confirmation_source: "telegram_button",
      telegram_user_id: clean(input.telegram_user_id),
    },
  },
}];

const item = $json || {};
const ok = item.success === true;
const ref = item.document_ref || item.document_id || "the quote";
const msg = ok
  ? `Quote sent successfully.\n\nDocument: ${ref}\nOrder: ${item.order_id || ""}`
  : `Quote was not sent.\n\n${Array.isArray(item.errors) ? item.errors.join("; ") : (item.message || item.error || "The backend did not confirm delivery.")}`;
return [{ json: { chat_id: item.chat_id || $node["Code - Normalize Document Send Callback"].json.chat_id, message: msg } }];

return [{
  json: {
    chat_id: $json.chat_id,
    message: `Quote send cancelled.\n\nOrder: ${$json.order_id}\nDocument: ${$json.document_id}`,
  },
}];

return [{
  json: {
    chat_id: $json.chat_id,
    message: $json.validation_error || "Invalid quote send button data. No document was sent.",
  },
}];

